#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI mx=30005;
int n,m;
vector<int>g[mx];
int f[mx][16],d[mx];
void dfs(int u,int fa)
{
	d[u]=d[fa]+1;
	f[u][0]=fa;
	FOR(i,1,15)
	{
		f[u][i]=f[f[u][i-1]][i-1];
	}
	FOI(v,g[u])
	{
		if(v==fa)continue;
		dfs(v,u);
	}
}
int lca(int x,int y)
{
	if(d[x]<d[y])swap(x,y);
	ROF(i,15,0)
	{
		if(d[f[x][i]]>=d[y])
		{
			x=f[x][i];
		}
	}
	if(x==y)return x;
	ROF(i,15,0)
	{
		if(f[x][i]!=f[y][i])
		{
			x=f[x][i];
			y=f[y][i];
		}
	}
	return f[x][0];
}
int dis(int x,int y)
{
	int l=lca(x,y);
	return d[x]+d[y]-2*d[l];
}
int q[mx];
signed main(void)
{
	IOS
	cin>>n;
	FOR(i,1,n-1)
	{
		int u,v;
		cin>>u>>v;
		g[u].pb(v);
		g[v].pb(u);
	}
	dfs(1,0);
	cin>>m;
	FOR(i,1,m)
	{
		cin>>q[i];
	}
	int res=0;
	FOR(i,2,m)
	{
		res+=dis(q[i-1],q[i]);
	}
	cout<<res;
	return 0;
}
